scwin.onpageload = function () {
  scwin.f_FieldClear();

  //이 화면이 팝업인 경우 파라미터 받기 
  scwin.params = $c.data.getParameter($p);
  scwin.params.data = scwin.params.data || [];

  // 팝업인 경우 class 변경
  var isPopup = scwin.params.data && scwin.params.data.length > 0;
  if (isPopup) {
    gp_contents.removeClass("sub_contents");
    gp_contents.addClass("pop_contents");
  } else {
    gp_contents.removeClass("pop_contents");
    gp_contents.addClass("sub_contents");
  }
  if (scwin.params.data[0] != null && scwin.params.data[0] != "" && scwin.params.data[0] != "undefined") {
    var odrNo = scwin.params.data[0].trim();
    dma_cndInfo.set("odrNo", odrNo); // DataMap에 오더번호 세팅
    ed_cnd_odrNo.setValue(odrNo);
    gr_cntrInfo.setGridHeight(180); // 사이즈 조정

    if (ed_cnd_odrNo.getValue() != "") {
      btn_close.show();
      $c.gus.cfDisableObjects($p, [ed_cnd_odrNo]);
      scwin.f_Retrieve();
    }
  } else {
    // 그리드 세팅
    scwin.f_SetGridHeader(dma_cndInfo.get("odrNo"), ds_cntrInfo.getCellData(0, "impExpDomesticClsCd"));
  }
};

//-------------------------------------------------------------------------
// 그리드뷰 세팅
//-------------------------------------------------------------------------
scwin.f_SetGridHeader = function (odrNo, impExpClsCd) {
  // 기본
  const DEFAULT_COLUMN_VISIBLE = {
    "bookingNo": false,
    "impTemper": true,
    // 온도(수입)
    "impDryYn": true,
    // DRY여부(수입)
    "impWt": true,
    // 중량(수입)
    "impDangerCd": true,
    // 위험물코드(수입)
    "impSealNo": true,
    // Seal-No(수입)
    "impOverLength": true,
    // 초과길이(수입)
    "impOverWidTh": true,
    // 초과폭(수입)
    "impOverHeight": true,
    // 초과높이(수입)
    "expTemper": true,
    // 온도(수출)
    "dryYn": true,
    // DRY여부(수출)
    "expWt": true,
    // 중량(수출)	
    "expDangerCd": true,
    // 위험물코드(수출)
    "expSealNo": true,
    // Seal-No(수출)
    "expOverLength": true,
    // 초과길이(수출)
    "expOverWidth": true,
    // 초과폭(수출)
    "expOverHeight": true // 초과높이(수출)
  };
  // 수입
  const IMP_COLUMN_VISIBLE = {
    "bookingNo": false,
    "impTemper": true,
    "impDryYn": true,
    "impWt": true,
    "impDangerCd": true,
    "impSealNo": true,
    "impOverLength": true,
    "impOverWidTh": true,
    "impOverHeight": true,
    "expTemper": false,
    "dryYn": false,
    "expWt": false,
    "expDangerCd": false,
    "expSealNo": false,
    "expOverLength": false,
    "expOverWidth": false,
    "expOverHeight": false
  };
  // 수출: 수출인 경우, 셔틀인 경우는 수출을 default로 보여줄 것
  const EXP_COLUMN_VISIBLE = {
    "bookingNo": true,
    "impTemper": false,
    "impDryYn": false,
    "impWt": false,
    "impDangerCd": false,
    "impSealNo": false,
    "impOverLength": false,
    "impOverWidTh": false,
    "impOverHeight": false,
    "expTemper": true,
    "dryYn": true,
    "expWt": true,
    "expDangerCd": true,
    "expSealNo": true,
    "expOverLength": true,
    "expOverWidth": true,
    "expOverHeight": true
  };
  let COLUMN_VISIBLE = {};
  if (odrNo != null && odrNo != "") COLUMN_VISIBLE = impExpClsCd == DsConstants.IMP_CD ? IMP_COLUMN_VISIBLE : EXP_COLUMN_VISIBLE;else COLUMN_VISIBLE = DEFAULT_COLUMN_VISIBLE;

  // 조건별 그리드뷰 컬럼 visible 세팅
  Object.keys(COLUMN_VISIBLE).forEach(function (colId) {
    gr_cntrInfo.setColumnVisible(colId, COLUMN_VISIBLE[colId]);
  });
  gr_cntrInfo.redrawColumn();
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_cndArea, null);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  let rtn = await $c.gus.cfValidate($p, [tbl_cndArea]);
  if (rtn) {
    scwin.retrieveYn = "Y";
    $c.sbm.execute($p, sbm_retrieve);
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  let con = await $c.win.confirm($p, MSG_CM_CRM_001); //  저장하시겠습니까?
  if (con) {
    if (ds_cntrInfo.getModifiedIndex().length == 0) {
      $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_001, ["컨테이너오더"])); // @은(는) 변경된 사항이 없습니다.
      return;
    }
    let rtn = await $c.gus.cfValidate($p, [gr_cntrInfo]);
    if (rtn) {
      scwin.f_setValueBeforeSave(); // 저장하기전에 값 세팅
      $c.sbm.execute($p, sbm_save);
    }
  }
};

//-------------------------------------------------------------------------
// 저장하기전에 값 세팅
//    - 부두간 TS인 경우 : 수입온도를 수출온도에도 세팅해야함
//-------------------------------------------------------------------------
scwin.f_setValueBeforeSave = function () {
  let cntrInfoRows = ds_cntrInfo.getRowCount();
  if (cntrInfoRows > 0) {
    let odrKndCd = ds_cntrInfo.getCellData(0, "odrKndCd"); //오더종류

    //부두간 TS
    if (odrKndCd == DsConstants.ODR_KND_CD_TS_ODR) {
      for (let i = 0; i < cntrInfoRows; i++) {
        ds_cntrInfo.setCellData(i, "expTemper", ds_cntrInfo.getCellData(i, "impTemper"));
      }
    }
  }
};

//-------------------------------------------------------------------------
// 행 취소
//-------------------------------------------------------------------------
scwin.f_UndoRow = function () {
  if (ds_cntrInfo.getRowCount() > 0) {
    $c.data.undoRow($p, ds_cntrInfo, "Y");
  }
};

//-------------------------------------------------------------------------
// 닫기
//-------------------------------------------------------------------------
scwin.f_Close = function () {
  var arrRtnVal = new Array();
  arrRtnVal[0] = "N/A";
  arrRtnVal[1] = scwin.saveYn;
  $c.win.closePopup($p, arrRtnVal);
};

//-------------------------------------------------------------------------
// 컨테이너 type이 'RF'인 경우, 온도와 dry여부 둘 중에 하나만 입력해야 함
//-------------------------------------------------------------------------
scwin.f_SetTemperDryByRFCntr = function (ds, gr, row) {
  var type = ds.getCellData(row, "cntrTypCd"); // 컨테이너 type
  var impTemper = ds.getCellData(row, "impTemper"); // 수입온도
  var impDryYn = ds.getCellData(row, "impDryYn"); // 수입dry 여부
  var expTemper = ds.getCellData(row, "expTemper"); // 수출온도
  var expDryYn = ds.getCellData(row, "dryYn"); // 수출dry 여부

  if (type == DsConstants.CNTR_TYP_CD_RF) {
    // 수입
    if (!$c.gus.cfIsNull($p, impTemper) && impDryYn == DsConstants.YN_NO) {
      gr.setColumnDisabled("impTemper", false);
      gr.setColumnDisabled("impDryYn", true);
    } else if ($c.gus.cfIsNull($p, impTemper) && impDryYn == DsConstants.YN_YES) {
      gr.setColumnDisabled("impTemper", true);
      gr.setColumnDisabled("impDryYn", false);
    } else {
      gr.setColumnDisabled("impTemper", false);
      gr.setColumnDisabled("impDryYn", false);
    }

    // 수출
    if (!$c.gus.cfIsNull($p, expTemper) && expDryYn == DsConstants.YN_NO) {
      gr.setColumnDisabled("expTemper", false);
      gr.setColumnDisabled("dryYn", true);
    } else if ($c.gus.cfIsNull($p, expTemper) && expDryYn == DsConstants.YN_YES) {
      gr.setColumnDisabled("expTemper", true);
      gr.setColumnDisabled("dryYn", false);
    } else {
      gr.setColumnDisabled("expTemper", false);
      gr.setColumnDisabled("dryYn", false);
    }
  } else {
    ds.setCellData(row, "impTemper", "");
    ds.setCellData(row, "impDryYn", 0);
    ds.setCellData(row, "expTemper", "");
    ds.setCellData(row, "dryYn", 0);
    gr.setColumnDisabled("impTemper", true);
    gr.setColumnDisabled("impDryYn", true);
    gr.setColumnDisabled("expTemper", true);
    gr.setColumnDisabled("dryYn", true);
  }
};

//------------------------------------------------------------------------
// 항구 조회 Popup 처리 : 그리드에서 항구코드 입력시 팝업 호출 
//   - AS-IS : gr_cntrInfo의 OnPopup 이벤트
//------------------------------------------------------------------------
scwin.fn_portPopup = function (rowIndex, columnId) {
  scwin.f_openCommPopUpGrid(rowIndex, "F");
};

//-------------------------------------------------------------------------
// 항구 조회 Popup 처리 : 그리드에서 입력된 코드정보로 항구를 조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = function (row, pClose, pAllSearch) {
  let pCode = ds_cntrInfo.getCellData(row, "portCd");
  let pName = "";

  // 팝업 열기 전에 portCd, portNm 미리 공백으로 세팅
  // (팝업 닫아도 공백 유지, 선택하면 callback에서 덮어씀)
  ds_cntrInfo.setCellData(row, "portCd", "");
  ds_cntrInfo.setCellData(row, "portNm", "");
  var portCallback = function (ret) {
    $c.gus.cfSetGridReturnValue($p, ret, ds_cntrInfo, row, "portCd", "portNm");
  };

  // Select ID : retrievePortInfo
  udc_comCodePort.cfCommonPopUp(portCallback // 팝업 콜백 리턴결과 Array 형태로 SQL Select 순서로 Return
  , pCode // 화면에서의 ??? Code Element의 Value
  , pName // 화면에서의 ??? Name Element의 Value
  , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
  , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) 	MAX:10     null(2)   "5"
  , null // Title명's                         	null    "100,200"
  , null // 보여주는 각 컬럼들의 폭               null    "100,200"
  , null // 컬럼중에서 숨기는 컬럼 지정           null    "7,8,9,10"		
  , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:12개까지 가능     null    "SHIP"
  , null // POP-UP 띄울때 원도우의 사용자 정의 폭              null    "500"
  , null // POP-UP 띄울때 윈도우의 사용자 정의 높이             null    "600"
  , null // 윈도우 위치 Y좌표
  , null // 윈도우 위치 X좌표  
  , null // 중복체크여부
  , pAllSearch // 전체검색허용여부 ("F")
  , "항구,항구코드,항구명" // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)        null    "Win타이틀,검색어1,검색어2"
  , null // Data건수가 0건일때 Window를 띄우지 않음 리턴
  );
};

///////////////////////////////////////////// S U B M I S S I O N    E V E N T /////////////////////////////////////////

// 조회
scwin.sbm_retrieve_submitdone = function (e) {
  scwin.retrieveYn = "N";
  var rowCnt = ds_cntrInfo.getRowCount();
  if (rowCnt == 0) {
    $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_003)); // 해당되는 자료가 존재하지 않습니다.
    return;
  }

  // 그리드 세팅
  scwin.f_SetGridHeader(ds_cntrInfo.getCellData(0, "odrNo"), ds_cntrInfo.getCellData(0, "impExpDomesticClsCd"));
  scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, 0);
  totalRows.setValue(rowCnt);
};

// 저장
scwin.sbm_save_submitdone = function (e) {
  $c.win.alert($p, $c.data.getMessage($p, MSG_CM_INF_001)); // 성공적으로 저장하였습니다.

  scwin.saveYn = "Y"; //팝업으로 띄워졌을때 parent에 보내는 값
  scwin.f_Retrieve();
};

///////////////////////////////////////////// C O M P O N E N T   E V E N T /////////////////////////////////////////

// 그리드 행 인덱스 변경시
scwin.ds_cntrInfo_onrowpositionchange = function (info) {
  if (scwin.retrieveYn == "N") {
    scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, info.newRowIndex);
  }
};

// 그리드 셀 클릭
scwin.gr_cntrInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (rowIndex >= 0) {
    switch (gr_cntrInfo.getColumnID(columnIndex)) {
      case "impDryYn":
      case "dryYn":
        scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
        break;
    }
  }
};

// onbeforeedit - oldData 저장 (가우스 OnExit의 olddata 파라미터 역할)
scwin.gr_cntrInfo_onbeforeedit = function (rowIndex, columnIndex, value) {
  let colID = gr_cntrInfo.getColumnID(columnIndex);
  if (colID == "portCd") {
    scwin._portCdOldData = value;
  }
};

// 그리드 셀 데이터 편집 후 FocusOut
//  - AS-IS : gr_cntrInfo 의 onExit 이벤트
scwin.gr_cntrInfo_onafteredit = function (rowIndex, columnIndex, value) {
  let colID = gr_cntrInfo.getColumnID(columnIndex);
  switch (colID) {
    case "impWt":
    case "expWt":
      let num = Number(value);
      if (isNaN(num)) {
        ds_cntrInfo.setCellData(rowIndex, colID, "");
        return;
      }
      if (num < 0) num = Math.abs(num);
      let factor = Math.pow(10, 3); // 소수점 3자리 버림
      num = Math.floor(num * factor) / factor;
      ds_cntrInfo.setCellData(rowIndex, colID, num);
      break;
    case "portCd":
      // 팝업
      if (value != "" && value != scwin._portCdOldData) {
        ds_cntrInfo.setCellData(rowIndex, "portNm", "");
        scwin.f_openCommPopUpGrid(rowIndex, "T");
      } else if (value == "") {
        ds_cntrInfo.setCellData(rowIndex, "portCd", "");
        ds_cntrInfo.setCellData(rowIndex, "portNm", "");
      }
      break;
    case "impTemper": // 수입온도
    case "expTemper":
      // 수출온도
      scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
      break;
  }
};

// 그리드뷰 keydown
//  - 중량(수출,수입 - impWt, expWt) 컬럼의 형식 제한 (#,###.000[floor])
scwin.gr_cntrInfo_onkeydown = function (e) {
  let colID = gr_cntrInfo.getFocusedColumnID();
  if (colID != "impWt" && colID != "expWt") return; // 대상 컬럼만 처리

  let key = e.key;
  let input = e.target;
  let val = input.value || "";

  // 콤마 제거
  let raw = val.replace(/,/g, "");
  let cursorPos = input.selectionStart;

  // 제어키 허용
  const controlKeys = ["Backspace", "Delete", "Tab", "Enter", "Home", "End", "ArrowLeft", "ArrowRight", "ArrowUp", "ArrowDown"];
  if (controlKeys.includes(key)) return;

  // 숫자 입력
  if (key >= "0" && key <= "9") {
    // 입력 값 가상 생성
    let nextRaw = raw.substring(0, cursorPos) + key + raw.substring(cursorPos);

    // 소수점 3자리 제한
    if (nextRaw.includes(".")) {
      let dotIndex = nextRaw.indexOf(".");
      let decimalPart = nextRaw.substring(dotIndex + 1);
      if (decimalPart.length > 3) {
        e.preventDefault();
        return;
      }
    }
    return;
  }

  // 소수점 입력
  if (key == ".") {
    // 이미 있으면 차단
    if (raw.includes(".")) {
      e.preventDefault();
      return;
    }
    return;
  }

  // Ctrl + C / V 허용
  if (e.ctrlKey && ["c", "v"].includes(key.toLowerCase())) return;

  // 그 외 전부 차단
  e.preventDefault();
};

// 오더번호 대문자
scwin.ed_cnd_odrNo_onkeyup = function (e) {
  this.setValue(e.target.value.toUpperCase());
};

// 오더번호 Enter
scwin.ed_cnd_odrNo_onkeydown = function (e) {
  if (e.keyCode == 13) {
    scwin.f_Retrieve();
  }
};

// 컨테이너번호 대문자
scwin.ed_cnd_cntrNo_onkeyup = function (e) {
  this.setValue(e.target.value.toUpperCase());
};

// 컨테이너번호 Enter
scwin.ed_cnd_cntrNo_onkeydown = function (e) {
  if (e.keyCode == 13) {
    scwin.f_Retrieve();
  }
};
